def update_nav_in_file(path: Path, root: bool):
    if not path.exists():
        return False
    html = path.read_text(encoding='utf-8', errors='ignore')
    nav = NAV_ROOT if root else NAV_SUB
    new_html = re.sub(r'<nav class="site-nav"[^>]*>.*?</nav>', nav, html, count=1, flags=re.S)
    if new_html == html:
        # fallback for any simple nav
        new_html = re.sub(r'<nav[^>]*>.*?</nav>', nav, html, count=1, flags=re.S)
    if new_html != html:
        path.write_text(new_html, encoding='utf-8')
        return True
    return False

# Update nav on root HTML files and publication pages
for p in ROOT.glob('*.html'):
    update_nav_in_file(p, root=True)
for p in (ROOT / 'publications').glob('*.html') if (ROOT / 'publications').exists() else []:
    update_nav_in_file(p, root=False)

# Update index title and main body
html = INDEX_PATH.read_text(encoding='utf-8', errors='ignore')
html = re.sub(r'<title>.*?</title>', '<title>Indoor Positioning Hub | Ahmed Mansour</title>', html, count=1, flags=re.S)
html = re.sub(r'<meta name="description" content="[^"]*">', '<meta name="description" content="Indoor Positioning Hub by Ahmed Mansour: indoor positioning, localization, navigation, Wi-Fi fingerprinting, PDR, mobile crowdsensing, radio maps, publications, PDFs, citation resources, datasets, and code.">', html, count=1)
html = re.sub(r'<main\b[^>]*>.*?</main>', HOME_MAIN, html, count=1, flags=re.S)
INDEX_PATH.write_text(html, encoding='utf-8')

# Add CSS override block, replacing prior v21 block on rerun
CSS_PATH.parent.mkdir(parents=True, exist_ok=True)
css = CSS_PATH.read_text(encoding='utf-8', errors='ignore') if CSS_PATH.exists() else ''
css = re.sub(r'/\* === Homepage profile restore and definitions v21 START === \*/.*?/\* === Homepage profile restore and definitions v21 END === \*/', '', css, flags=re.S)
css = css.rstrip() + '\n\n' + CSS_BLOCK.strip() + '\n'
CSS_PATH.write_text(css, encoding='utf-8')

print('Done: restored profile-photo homepage, added definitions, restored thematic-map wording, and kept the v20 visual style.')
